import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    idx = 0
    N = int(data[idx])
    idx += 1

    D = [[0] * (N + 1) for _ in range(N + 1)]

    for i in range(1, N):
        for j in range(i + 1, N + 1):
            D[i][j] = int(data[idx])
            idx += 1

    # Bitmask DP for maximum weight matching
    # dp[mask] = maximum weight of matching for the subset of vertices represented by mask
    dp = [0] * (1 << N)

    for mask in range(1 << N):
        # Try all pairs of vertices that are not used in the mask
        # and are not already used
        for i in range(N):
            if not (mask & (1 << i)):
                for j in range(i + 1, N):
                    if not (mask & (1 << j)):
                        new_mask = mask | (1 << i) | (1 << j)
                        dp[new_mask] = max(dp[new_mask], dp[mask] + D[i + 1][j + 1])

    print(dp[(1 << N) - 1])

if __name__ == "__main__":
    main()
